    print("  - Bonding for persistent pairing")
    print("  - Input validation on all writes")
    print("  - Rate limiting per connection")
    print("  - Connection timeout (5 min idle)")
    print("  - Max {} concurrent connections".format(_MAX_CONNECTIONS))
    print()

    device = SecureBLEDevice(device_name="ESP32-IoT-Secure")

    # Run the main loop with 10-second sensor update interval
    device.run(sensor_interval_s=10)


